/// Default keychain service-name prefix for the session token (one per
/// tenant). The matching account-name is `session_token`. The Tauri
/// shell reads this entry at startup to know the bearer token to
/// present.
const SESSION_TOKEN_ACCOUNT: &str = "session_token";

fn keychain_service_for(tenant: &str) -> String {
    format!("aberp.nav.{tenant}")
}

/// Persisted artifacts (cert PEM + key PEM + fingerprint) for the
/// loopback HTTPS listener live in `~/.aberp/serve/<tenant>/`. ADR-0007
/// §Transport names "next to the keychain material" — for the
/// per-platform Keychain/Credential-Manager/secret-service backends
/// "next to" is the user-home convention. A future ADR can pick a
/// per-OS path if needed; for now the user-home posture works on all
/// three platforms.
fn serve_artifacts_dir(tenant: &str) -> Result<PathBuf> {
    let home = dirs_home_or_loud_fail()?;
    Ok(home.join(".aberp").join("serve").join(tenant))
}

/// We deliberately do NOT import the `dirs` crate (one more dep, one
/// more supply-chain surface). `std::env::var("HOME")` covers macOS
/// and Linux; `USERPROFILE` covers Windows. Loud-fail if neither is
/// set per CLAUDE.md rule 12.
fn dirs_home_or_loud_fail() -> Result<PathBuf> {
    if let Ok(h) = std::env::var("HOME") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    if let Ok(h) = std::env::var("USERPROFILE") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    Err(anyhow!(
        "neither HOME nor USERPROFILE is set — cannot locate ~/.aberp/serve/<tenant>/"
    ))
}

pub fn run(args: &ServeArgs) -> Result<()> {
    let _span = tracing::info_span!(
        "serve",
        tenant = %args.tenant,
        port = args.port,
        db = %args.db.display(),
    )
    .entered();

    // 1. Resolve tenant id + load session token from the keychain.
    let tenant = TenantId::new(args.tenant.clone()).ok_or_else(|| {
        anyhow!(
            "--tenant value '{}' is empty or has a null byte",
            args.tenant
        )
    })?;
    let session_token = load_or_create_session_token(&args.tenant)?;

    // 2. Resolve / generate the loopback cert + key.
    let artifacts_dir = serve_artifacts_dir(&args.tenant)?;
    std::fs::create_dir_all(&artifacts_dir).with_context(|| {
        format!(
            "create serve artifacts directory at {}",
            artifacts_dir.display()
        )
    })?;
    let cert_path = artifacts_dir.join("loopback.crt.pem");
    let key_path = artifacts_dir.join("loopback.key.pem");
    let fingerprint_path = artifacts_dir.join("loopback.fingerprint.sha256");
    let (cert_pem, key_pem, fingerprint_hex) =
        ensure_loopback_cert(&cert_path, &key_path, &fingerprint_path)?;
    tracing::info!(
        cert = %cert_path.display(),
        fingerprint = %fingerprint_hex,
        "loopback TLS certificate ready"
    );

    // 3. Build the rustls server config.
    let rustls_config = build_rustls_config(&cert_pem, &key_pem)?;

    // 4. Build the shared application state.
    let binary_hash_bytes = binary_hash::compute().context("compute binary hash")?;
    let state = AppState {
        db_path: Arc::new(args.db.clone()),
        tenant,
        binary_hash: binary_hash_bytes,
        session_token: Arc::new(session_token.clone()),
    };

    // 5. Build the axum router.
    let app = build_router(state);

    // 6. Build a tokio current-thread runtime (matches the rest of
    //    the binary's blocking-CLI posture; the serve subcommand is
    //    long-running but we still avoid the multi-thread runtime
    //    overhead — one operator workstation, low concurrency).
    let runtime = tokio::runtime::Builder::new_multi_thread()
        .enable_all()
        .build()
        .context("build tokio multi-thread runtime for axum")?;

    // 7. Bind + serve.
    let addr: SocketAddr = format!("127.0.0.1:{}", args.port)
        .parse()
        .with_context(|| {
            format!(
                "parse loopback socket address 127.0.0.1:{} (port out of range?)",
                args.port
            )
        })?;
    tracing::info!(
        bind = %addr,
        fingerprint = %fingerprint_hex,
        session_token_first8 = &session_token[..8.min(session_token.len())],
        "starting HTTPS loopback listener — present \
         `Authorization: Bearer <session_token>` to authenticated routes; \
         verify TLS cert against the SHA-256 fingerprint"
    );
    println!(
        "aberp serve: https://{}/ (fingerprint sha256:{})",
        addr, fingerprint_hex
    );
    runtime.block_on(async move {
        let config = RustlsConfig::from_der(rustls_config.0, rustls_config.1)
            .await
            .context("build axum-server RustlsConfig")?;
        axum_server::bind_rustls(addr, config)
            .serve(app.into_make_service())
            .await
            .context("axum_server::bind_rustls(...).serve(...)")
    })?;

    Ok(())
}

// ── Cert / key / fingerprint persistence ─────────────────────────────

/// If the persisted artifacts already exist, read them. Otherwise
/// generate a fresh self-signed cert via `rcgen`, persist all three
/// artifacts (cert PEM, key PEM, hex fingerprint), and return them.
///
/// Returns the *PEM bytes* of cert and key (string-ish) and the hex
/// fingerprint string.
fn ensure_loopback_cert(
    cert_path: &Path,
    key_path: &Path,
    fingerprint_path: &Path,
) -> Result<(String, String, String)> {
    if cert_path.exists() && key_path.exists() {
        let cert_pem = std::fs::read_to_string(cert_path)
            .with_context(|| format!("read persisted cert PEM from {}", cert_path.display()))?;
        let key_pem = std::fs::read_to_string(key_path)
            .with_context(|| format!("read persisted key PEM from {}", key_path.display()))?;
        let fingerprint = compute_cert_fingerprint(&cert_pem)?;
        // Re-persist the fingerprint file even if it already exists —
        // a missing fingerprint file would otherwise be a confusing
        // first-startup-after-corrupted-state failure mode.
        std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
            format!(
                "write loopback fingerprint to {}",
                fingerprint_path.display()
            )
        })?;
        return Ok((cert_pem, key_pem, fingerprint));
    }

    // Generate fresh.
    let mut params = rcgen::CertificateParams::new(vec!["localhost".to_string()])
        .context("rcgen CertificateParams::new")?;
    let mut dn = DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, "ABERP loopback");
    params.distinguished_name = dn;
    params.key_usages = vec![
        KeyUsagePurpose::DigitalSignature,
        KeyUsagePurpose::KeyEncipherment,
    ];
    let key_pair = KeyPair::generate().context("rcgen KeyPair::generate")?;
    let cert = params
        .self_signed(&key_pair)
        .context("rcgen CertificateParams::self_signed")?;

    let cert_pem = cert.pem();
    let key_pem = key_pair.serialize_pem();
    let fingerprint = compute_cert_fingerprint(&cert_pem)?;

    std::fs::write(cert_path, &cert_pem)
        .with_context(|| format!("write loopback cert PEM to {}", cert_path.display()))?;
    std::fs::write(key_path, &key_pem)
        .with_context(|| format!("write loopback key PEM to {}", key_path.display()))?;
    std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
        format!(
            "write loopback fingerprint to {}",
            fingerprint_path.display()
        )
    })?;

    // Tighten the key file's permissions on POSIX. On Windows the call
    // is a no-op; we silently skip it.
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let mut perms = std::fs::metadata(key_path)
            .with_context(|| format!("stat {}", key_path.display()))?
            .permissions();
        perms.set_mode(0o600);
        std::fs::set_permissions(key_path, perms)
            .with_context(|| format!("chmod 0600 {}", key_path.display()))?;
    }

    Ok((cert_pem, key_pem, fingerprint))
}

/// SHA-256 fingerprint of the **DER body** of the first cert in a PEM
/// bundle, hex-encoded. Matches the format `openssl x509 -fingerprint
/// -sha256 -noout -in cert.pem` produces (lower-case, no colons).
fn compute_cert_fingerprint(cert_pem: &str) -> Result<String> {
    let mut bytes = cert_pem.as_bytes();
    let cert_der = rustls_pemfile::certs(&mut bytes)
        .next()
        .ok_or_else(|| anyhow!("no certificate found in PEM bundle"))?
        .context("parse certificate PEM")?;
    let mut hasher = Sha256::new();
    hasher.update(&cert_der);
    Ok(hex::encode(hasher.finalize()))
}

/// Parse the PEM bytes into the `Vec<u8>` DER pair `axum_server`'s
/// `RustlsConfig::from_der` wants.
fn build_rustls_config(cert_pem: &str, key_pem: &str) -> Result<(Vec<Vec<u8>>, Vec<u8>)> {
    let mut cert_bytes = cert_pem.as_bytes();
    let certs: Vec<Vec<u8>> = rustls_pemfile::certs(&mut cert_bytes)
        .map(|c| c.map(|der| der.to_vec()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse loopback cert PEM")?;
    if certs.is_empty() {
        return Err(anyhow!("loopback cert PEM contained no certificates"));
    }
    let mut key_bytes = key_pem.as_bytes();
    let key = rustls_pemfile::private_key(&mut key_bytes)
        .context("parse loopback key PEM")?
        .ok_or_else(|| anyhow!("loopback key PEM contained no private key"))?;
    Ok((certs, key.secret_der().to_vec()))
}

// ── Session token in the OS keychain ─────────────────────────────────

/// Look up the session token in the OS keychain for this tenant; if
/// absent, generate a fresh 256-bit random token (hex-encoded) and
/// persist it.
fn load_or_create_session_token(tenant: &str) -> Result<String> {
    let service = keychain_service_for(tenant);
    let entry = keyring::Entry::new(&service, SESSION_TOKEN_ACCOUNT)
        .context("build keyring::Entry for session token")?;
    match entry.get_password() {
        Ok(existing) if !existing.is_empty() => Ok(existing),
        Ok(_) | Err(keyring::Error::NoEntry) => {
            let fresh = generate_session_token();
            entry
                .set_password(&fresh)
                .context("write fresh session token to OS keychain")?;
            tracing::info!(
                tenant = tenant,
                "minted fresh session token in OS keychain (account `session_token`)"
            );
            Ok(fresh)
        }
        Err(e) => Err(anyhow!("keychain access for session token failed: {e}")),
    }
}

/// 32 random bytes from the OS RNG, hex-encoded. We do not pull in
/// `rand` for this — `std::time::SystemTime::now()` is the cheap
/// source for one-shot key material on a single workstation, mixed
/// with a per-process ULID. A proper rotation flow with a real RNG
/// can land when the operator-action surface needs it; for the first
/// MVP token a 256-bit value derived from system entropy is
/// sufficient.
///
/// Per CLAUDE.md rule 12, we name the trade-off loud: this is NOT a
/// cryptographic key. It is a single-workstation bearer secret that
/// gates one local HTTPS endpoint behind the OS-keychain trust
/// boundary the rest of ABERP already lives behind. A future
/// PR-9-1.5 (or session 12) can swap this for a `rand`-sourced
/// equivalent.
fn generate_session_token() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now_nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0u128);
    let ulid_bytes = ulid::Ulid::new().to_bytes();
    let pid = std::process::id();
    let mut hasher = Sha256::new();
    hasher.update(now_nanos.to_le_bytes());
    hasher.update(ulid_bytes);
    hasher.update(pid.to_le_bytes());
    hex::encode(hasher.finalize())
}

// ── Axum router + handlers ───────────────────────────────────────────

#[derive(Clone)]
struct AppState {
    db_path: Arc<PathBuf>,
    tenant: TenantId,
    binary_hash: aberp_audit_ledger::BinaryHash,
    session_token: Arc<String>,
}

fn build_router(state: AppState) -> Router {
    Router::new()
        .route("/health", get(handle_health))
        .route("/invoices", get(handle_list_invoices))
        .route("/invoices/:id", get(handle_get_invoice))
        .route("/audit/:invoice_id", get(handle_get_audit))
        .with_state(state)
}

#[derive(Serialize)]
struct HealthResponse {
    ok: bool,
    binary_hash: String,
    nav_xsd_version: &'static str,
}

async fn handle_health(State(state): State<AppState>) -> Json<HealthResponse> {
    Json(HealthResponse {
        ok: true,
        binary_hash: hex::encode(state.binary_hash.as_bytes()),
        nav_xsd_version: aberp_nav_xsd_validator::NAV_XSD_VERSION,
    })
}

/// PR-28 / ADR-0036 §9 — typed wire shape for the eleven UI labels
/// emitted by `InvoiceTrace::derive_state`. Replaces the pre-PR-28
/// `&'static str` ladder per the §9 named-deferred trigger.
///
/// `Serialize` produces JSON strings matching the variant names
/// exactly (no `#[serde(rename_all = ...)]` — variants are already
/// PascalCase, matching the SPA's `InvoiceState` string union in
/// `apps/aberp-ui/ui/src/lib/api.ts`). Variant-name drift between
/// this enum and the SPA mirror surfaces at three layers per
/// CLAUDE.md rule 12: the Rust-side `invoice_state_wire_shape_pins_
/// pascalcase_strings` test pins each variant's JSON form loud; the
/// SPA's `Record<InvoiceState, LabelMeta>` table fails `npm run
/// check` on a missing key; the module-load runtime check in
/// `labels.ts` throws on a `LIFECYCLE_ORDER` divergence.
///
/// Variants kept in lifecycle order matching ADR-0036 §3's priority-
/// ladder inversion for readability; the discriminant order has no
/// wire impact (serde emits the variant identifier).
///
/// `Debug` + `PartialEq` + `Eq` + `Clone` + `Copy` keep the test
/// assertions ergonomic (the parameterised label-table test compares
/// against literal variants via `assert_eq!`).
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
enum InvoiceState {
    Unknown,
    Ready,
    Pending,
    PendingNavExists,
    Submitted,
    Recovered,
    Finalized,
    Rejected,
    Storno,
    Amended,
    Abandoned,
}

#[derive(Serialize)]
struct InvoiceListItem {
    invoice_id: String,
    sequence_number: u64,
    fiscal_year: i32,
    state: InvoiceState,
    total_gross: Option<i64>,
    /// PR-31 / session-35 — chain-link affordance for list rows
    /// (session-30-named Option M). `true` iff this invoice is the
    /// base of at least one `InvoiceStornoIssued` or
    /// `InvoiceModificationIssued` chain entry; mirrors
    /// `InvoiceTrace::is_storno_base || is_amended_base`. The SPA
    /// renders a small `↘` badge next to the state chip when this
    /// flag is true so an inspector can see at a glance which rows
    /// have a chain history without opening the detail modal. The
    /// flag is redundant-by-construction with `state ∈ {Storno,
    /// Amended}` for invoices that have only ever been the base of
    /// one chain kind; it carries additional signal when an invoice
    /// is the base of BOTH an amendment AND a storno (which the
    /// `derive_state` ladder collapses to `Storno` per ADR-0036 §3,
    /// hiding the prior amendment history at the state chip). Pinned
    /// by `list_invoices_emits_has_chain_children`.
    has_chain_children: bool,
}

#[derive(Serialize)]
struct InvoiceDetailResponse {
    invoice_id: String,
    sequence_number: u64,
    fiscal_year: i32,
    state: InvoiceState,
    total_gross: Option<i64>,
    audit_entries: Vec<AuditEntryView>,
    /// PR-32 / session-36 — chain-children list (Option T). For an
    /// invoice that is the BASE of at least one chain entry, this
    /// vector enumerates every storno / modification invoice issued
    /// against it, in ledger-walk (i.e., issuance) order. Empty for
    /// invoices with no chain children. The list-row badge from
    /// PR-31 (`has_chain_children: bool`) tells the inspector
    /// "this row has children"; this field tells the inspector
    /// "WHICH children." The SPA renders the list in a section
    /// between the meta-grid and the audit-trail table, each entry
    /// clickable via the same `onNavigate` callback as the
    /// audit-row chain-link affordance (PR-26). Pinned by
    /// `invoice_detail_emits_chain_children`.
    chain_children: Vec<ChainChildView>,
    /// PR-33 / session-37 — typed wire emit of the latest NAV ack
    /// for this invoice (Option Q). `Some(AckStatus)` when at least
    /// one `InvoiceAckStatus` audit entry has been written for the
    /// invoice; `None` for invoices with no ack yet (Draft / Pending
    /// / etc) and for the rare case where a persisted string fails
    /// to parse as one of the four NAV v3.0 values. The SPA's
    /// `InvoiceDetail.svelte` renders the value as a meta-grid row
    /// alongside Series #, Fiscal year, State, and Total (gross); a
    /// `null` wire form renders as `—`. Mirrors the
    /// `InvoiceTrace.last_ack_status` accumulator (which stays
    /// `Option<String>` to preserve the persisted form for
    /// `derive_state`'s string-keyed match per ADR-0036 §3 and the
    /// `audit_query.rs` `prior_last_ack_status` command-side
    /// posture). Pinned by `invoice_detail_emits_last_ack_status` +
    /// `ack_status_wire_shape_pins_uppercase_strings`.
    last_ack_status: Option<AckStatus>,
}

/// PR-32 / session-36 — chain-children list entry. One per storno /
/// modification invoice issued against a base.
#[derive(Serialize)]
struct ChainChildView {
    /// Which chain operation issued this child. Mirrors the two
    /// chain-link `EventKind` variants
    /// (`InvoiceStornoIssued` / `InvoiceModificationIssued`) under
    /// the same PascalCase wire shape as `InvoiceState` for SPA-
    /// side consumption (typed enum on the TS side per PR-28
    /// precedent).
    kind: ChainChildKind,
    /// The chain child's own invoice id (the `storno_invoice_id` /
    /// `modification_invoice_id` field from the chain-link payload
    /// per ADR-0023 / ADR-0024).
    invoice_id: String,
}

/// PR-32 / session-36 — typed kind discriminator for chain-children
/// rows. Mirrors the terminal `InvoiceState` labels rather than the
/// `EventKind` names so the SPA can render the same label set the
/// state chip uses (`labels.ts`).
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
enum ChainChildKind {
    Storno,
    Amended,
}

/// PR-33 / session-37 — typed wire mirror for the four NAV v3.0
/// `processingResult` values (Option Q). The audit-ledger stores the
/// NAV ack as a free `String` on `InvoiceAckStatusPayload.ack_status`
/// (per `apps/aberp/src/audit_payloads.rs`); the wire shape now
/// surfaces the latest-per-invoice value as a typed enum on
/// `InvoiceDetailResponse.last_ack_status` so the SPA reads "the
/// invoice's most-recent NAV ack" without parsing the audit-entries
/// payload soup. Continues the typed-enum precedent set by PR-28
/// (`InvoiceState`) and PR-32 (`ChainChildKind`).
///
/// `#[serde(rename_all = "UPPERCASE")]` matches the NAV wire literals
/// verbatim — see `ProcessingStatus` in
/// `crates/nav-transport/src/operations/query_transaction_status.rs`
/// for the same four strings on the inbound parse path. The four
/// values per ADR-0009 §2: two intermediate (`RECEIVED`,
/// `PROCESSING`) and two terminal (`SAVED`, `ABORTED`). The
/// deprecated `DONE` value is NOT represented — it does not appear
/// in NAV v3.0 and the inbound `from_nav_str` parse already rejects
/// it.
///
/// `Debug` + `PartialEq` + `Eq` + `Clone` + `Copy` keep test
/// assertions ergonomic (the per-variant wire-pin test compares
/// against literal variants via `assert_eq!`), mirroring `InvoiceState`'s
/// derive set.
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
#[serde(rename_all = "UPPERCASE")]
enum AckStatus {
    Received,
    Processing,
    Saved,
    Aborted,
}

/// PR-33 / session-37 — parse a persisted `InvoiceAckStatusPayload.ack_status`
/// string to the typed wire enum.
///
/// The stored values SHOULD always be one of the four NAV v3.0
/// strings — `query_transaction_status::ProcessingStatus::from_nav_str`
/// rejects every other value on the inbound parse path, so a stored
/// non-NAV string would indicate DB tampering OR a schema drift.
/// Returns `None` for unrecognised input rather than failing the
/// whole read endpoint; the audit-entries drill-down (PR-27) still
/// surfaces the raw string verbatim via the typed payload JSON, so
/// no information is lost at the operator surface.
///
/// Strict per-variant match (not a `serde_json::from_str` round-trip)
/// keeps the conversion local and avoids an allocation on the hot
/// path of `get_invoice_detail`.
fn parse_ack_status(s: &str) -> Option<AckStatus> {
    match s {
        "RECEIVED" => Some(AckStatus::Received),
        "PROCESSING" => Some(AckStatus::Processing),
        "SAVED" => Some(AckStatus::Saved),
        "ABORTED" => Some(AckStatus::Aborted),
        _ => None,
    }
}

#[derive(Serialize)]
struct AuditEntryView {
    seq: u64,
    kind: String,
    actor: String,
    /// PR-27 / session-31 lifted the "short view" posture: the wire
    /// shape now carries the full typed payload via the `payload`
    /// field below. The `/audit/:invoice_id` endpoint and the
    /// `/invoices/:id` endpoint return the same per-entry shape.
    occurred_at: String,
    /// PR-26 / session-30 — chain-link affordance for the detail
    /// modal. `Some(base_id)` for `InvoiceStornoIssued` /
    /// `InvoiceModificationIssued` entries (the typed payload's
    /// `base_invoice_id` field per ADR-0023 / ADR-0024); `None` for
    /// every other kind. Serialised as `null` for non-chain rows
    /// (matches `total_gross: Option<i64>`'s wire posture above so
    /// the SPA consumes a uniform `string | null`). The SPA's
    /// `InvoiceDetail.svelte` renders the field as a clickable
    /// navigation to the base invoice when present. Pinned by
    /// `audit_view_of_emits_chain_base_invoice_id`.
    chain_base_invoice_id: Option<String>,
    /// PR-27 / session-31 — full typed payload as raw JSON for the
    /// per-row drill-down in `InvoiceDetail.svelte`. The
    /// `audit_payloads::*` types serialise via `serde_json::to_vec`
    /// per F9 (closed in PR-6.1), so `entry.payload` bytes are
    /// always valid JSON; a malformed payload — which would
    /// indicate direct DB tampering — falls back to
    /// `Value::Null` so the SPA's pretty-printer renders `null`
    /// rather than crashing the view. The exposure matches the
    /// `aberp dump-audit-bundle` posture per the PR-27 lean: no
    /// redaction default (F43 bundle-redaction posture stays
    /// named-deferred; the SPA exposure is parity, not regression).
    /// Pinned by `audit_view_of_emits_typed_payload`.
    payload: serde_json::Value,
}

async fn handle_list_invoices(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match list_invoices(&state) {
        Ok(items) => Json(items).into_response(),
        Err(e) => internal_error("list_invoices", e),
    }
}

async fn handle_get_invoice(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match get_invoice_detail(&state, &invoice_id) {
        Ok(Some(detail)) => Json(detail).into_response(),
        Ok(None) => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!("no invoice found with id {invoice_id}"))),
        )
            .into_response(),
        Err(e) => internal_error("get_invoice_detail", e),
    }
}

async fn handle_get_audit(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match get_audit_for_invoice(&state, &invoice_id) {
        Ok(entries) if entries.is_empty() => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!(
                "no audit ledger entries for invoice id {invoice_id}"
            ))),
        )
            .into_response(),
        Ok(entries) => Json(entries).into_response(),
        Err(e) => internal_error("get_audit_for_invoice", e),
    }
}

/// Inspect the request's `Authorization` header against the expected
/// bearer token. Returns `Some(response)` if the request must be
/// rejected (no token, malformed token, mismatched token); returns
/// `None` if the request may proceed.
///
/// The `Option`-on-rejection shape (rather than `Result<(), Response>`)
/// avoids clippy's `result_large_err` lint — `Response` is ~128 bytes
/// and `Result` carries it in both arms. Semantically clearer too:
/// `Some(resp)` reads as "here is the rejection response."
fn check_bearer_rejection(headers: &HeaderMap, expected: &str) -> Option<Response> {
    let auth = headers
        .get(axum::http::header::AUTHORIZATION)
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if let Some(token) = auth.strip_prefix("Bearer ") {
        if constant_time_eq(token, expected) {
            return None;
        }
    }
    Some(
        (
            StatusCode::UNAUTHORIZED,
            Json(error_body("missing or invalid Bearer token".to_string())),
        )
            .into_response(),
    )
}

/// Constant-time string compare. A small loop is fine here — the
/// strings are O(64) bytes. We never want to leak token length via a
/// fast `==` exit, so we walk the longer of the two and accumulate.
fn constant_time_eq(a: &str, b: &str) -> bool {
    let a = a.as_bytes();
    let b = b.as_bytes();
    if a.len() != b.len() {
        return false;
    }
    let mut diff = 0u8;
    for i in 0..a.len() {
        diff |= a[i] ^ b[i];
    }
    diff == 0
}

fn internal_error(context_label: &'static str, e: anyhow::Error) -> Response {
    tracing::error!(error = %format!("{e:#}"), "internal error in {}", context_label);
    (
        StatusCode::INTERNAL_SERVER_ERROR,
        Json(error_body("internal error".to_string())),
    )
        .into_response()
}

#[derive(Serialize)]
struct ErrorBody {
    error: String,
}

fn error_body(error: String) -> ErrorBody {
    ErrorBody { error }
}

// ── Read paths over billing DB + audit ledger ────────────────────────

fn list_invoices(state: &AppState) -> Result<Vec<InvoiceListItem>> {
    // The audit ledger is the source of truth for "what invoices
    // exist." Walk every entry once; group by invoice_id; derive
    // state.
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), state.binary_hash)
        .context("open audit ledger for serve list")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    let mut by_invoice: std::collections::BTreeMap<String, InvoiceTrace> = Default::default();
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            by_invoice
                .entry(id.clone())
                .or_default()
                .merge_entry(entry, &id);
        }
        // PR-23 / ADR-0036 §4 — chain-link entries do not carry a
        // top-level `invoice_id` field; they carry
        // `storno_invoice_id` / `modification_invoice_id` (the
        // chain invoice's own id, which already enters `by_invoice`
        // via its own InvoiceSequenceReserved + InvoiceDraftCreated
        // pair) AND `base_invoice_id` (the chain link's anchor,
        // which is what flips the BASE invoice's trace into Storno
        // / Amended). Probe extracts both ids so this base-side
        // trace flip and the PR-32 chain-children walker (in
        // `get_invoice_detail`) share one parse per chain entry.
        if let Some(link) = extract_chain_link(entry) {
            let trace = by_invoice.entry(link.base_invoice_id).or_default();
            match link.kind {
                EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                _ => {}
            }
        }
    }

    // Load billing details for each invoice id.
    let mut items: Vec<InvoiceListItem> = Vec::new();
    let mut conn = Connection::open(&*state.db_path)
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    for (id, trace) in by_invoice {
        let (ready_invoice, _idem) = match read_invoice_row(&mut conn, &id)? {
            Some(pair) => pair,
            None => continue, // ledger has it but billing row gone — skip silently
        };
        items.push(InvoiceListItem {
            invoice_id: id,
            sequence_number: ready_invoice.sequence_number,
            fiscal_year: ready_invoice.fiscal_year,
            state: trace.derive_state(),
            total_gross: ready_invoice.total_gross().map(|h| h.as_i64()),
            has_chain_children: trace.is_storno_base || trace.is_amended_base,
        });
    }
    Ok(items)
}

fn get_invoice_detail(state: &AppState, invoice_id: &str) -> Result<Option<InvoiceDetailResponse>> {
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), state.binary_hash)
        .context("open audit ledger for serve detail")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    let mut trace = InvoiceTrace::default();
    let mut audit_entries: Vec<AuditEntryView> = Vec::new();
    let mut chain_children: Vec<ChainChildView> = Vec::new();
    let mut found_any = false;
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                found_any = true;
                trace.merge_entry(entry, invoice_id);
                audit_entries.push(audit_view_of(entry));
            }
        }
        // PR-23 / ADR-0036 §4 — chain-link entries: flip the
        // base's trace into Storno / Amended. Detail view is
        // queried by id, so we only flip when this id IS the
        // base. The chain-link entry itself does NOT appear in
        // `audit_entries` for the base's detail view — those
        // entries belong to the storno / modification invoice's
        // own audit lineage; the base's lineage references them
        // only via the derived state label per ADR-0009 §2.
        //
        // PR-32 / session-36 — same pass also collects the
        // chain CHILD's id into `chain_children` so the detail
        // modal can list "WHICH children" alongside the badge's
        // "has children." Ordering is ledger-walk order
        // (insertion order into `Vec`), which is monotonically
        // increasing seq per ADR-0008 — operator-meaningful as
        // "chain entries in the order they were issued."
        if let Some(link) = extract_chain_link(entry) {
            if link.base_invoice_id == invoice_id {
                found_any = true;
                match link.kind {
                    EventKind::InvoiceStornoIssued => {
                        trace.is_storno_base = true;
                        chain_children.push(ChainChildView {
                            kind: ChainChildKind::Storno,
                            invoice_id: link.child_invoice_id,
                        });
                    }
                    EventKind::InvoiceModificationIssued => {
                        trace.is_amended_base = true;
                        chain_children.push(ChainChildView {
                            kind: ChainChildKind::Amended,
                            invoice_id: link.child_invoice_id,
                        });
                    }
                    _ => {}
                }
            }
        }
    }

    let mut conn = Connection::open(&*state.db_path)
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let billing = read_invoice_row(&mut conn, invoice_id)?;

    if !found_any && billing.is_none() {
        return Ok(None);
    }

    let (sequence_number, fiscal_year, total_gross) = match billing {
        Some((ri, _idem)) => (
            ri.sequence_number,
            ri.fiscal_year,
            ri.total_gross().map(|h| h.as_i64()),
        ),
        None => (0, 0, None),
    };
    // PR-33 / session-37 — typed wire emit of the latest NAV ack
    // for this invoice. `trace.last_ack_status` carries the raw
    // persisted string from `InvoiceAckStatusPayload.ack_status`;
    // parse it to the four-valued `AckStatus` enum at the wire
    // boundary. Unknown strings fall through to `None` (the audit-
    // entries drill-down still exposes the raw value).
    let last_ack_status = trace
        .last_ack_status
        .as_deref()
        .and_then(parse_ack_status);
    Ok(Some(InvoiceDetailResponse {
        invoice_id: invoice_id.to_string(),
        sequence_number,
        fiscal_year,
        state: trace.derive_state(),
        total_gross,
        audit_entries,
        chain_children,
        last_ack_status,
    }))
}

fn get_audit_for_invoice(state: &AppState, invoice_id: &str) -> Result<Vec<AuditEntryView>> {
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), state.binary_hash)
        .context("open audit ledger for serve audit")?;
    let entries = ledger.entries().context("read audit ledger entries")?;
    let mut out = Vec::new();
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                out.push(audit_view_of(entry));
            }
        }
    }
    Ok(out)
}

fn audit_view_of(entry: &Entry) -> AuditEntryView {
    AuditEntryView {
        seq: entry.seq.as_u64(),
        kind: format!("{:?}", entry.kind),
        actor: entry.actor.user_id.clone(),
        // ADR-0008 §"Entry shape" names two timestamps: `time_wall`
        // (RFC3339, operator-readable) and `time_mono` (monotonic
        // nanos since process start, drift-immune). The serve view
        // wants the operator-readable form.
        occurred_at: entry.time_wall.to_string(),
        // PR-26 — reuse the existing chain-link probe. The probe
        // already short-circuits on kind first per ADR-0036 §4, so
        // the cost is bounded for non-chain entries. PR-32 widened
        // the probe's return to also carry the chain child id; the
        // audit-entry view consumes only the base id here.
        chain_base_invoice_id: extract_chain_link(entry).map(|link| link.base_invoice_id),
        // PR-27 — the full typed payload as raw JSON. Every
        // `audit_payloads::*` type serialises via `serde_json::to_vec`
        // (F9 — closed in PR-6.1) so the bytes always parse cleanly;
        // a malformed payload falls back to `Null` rather than
        // panicking, so a corrupted entry is inspector-visible per
        // CLAUDE.md rule 12.
        payload: serde_json::from_slice(&entry.payload).unwrap_or(serde_json::Value::Null),
    }
}

/// Scoped read tx + billing lookup; returns None if the row is not
/// present.
fn read_invoice_row(
    conn: &mut Connection,
    invoice_id: &str,
) -> Result<Option<(ReadyInvoice, billing::IdempotencyKey)>> {
    let tx = conn
        .transaction()
        .context("begin read transaction for invoice lookup (serve)")?;
    let pair = billing::load_ready_invoice_by_id(&tx, invoice_id)
        .context("billing::load_ready_invoice_by_id (serve)")?;
    tx.commit().context("commit read transaction (serve)")?;
    Ok(pair)
}

// ── State derivation from the audit-ledger trace ─────────────────────

/// Per-invoice accumulator for the audit-ledger walk.
///
/// PR-23 / ADR-0036 §2 extends this with four new fact-bits over
/// the pre-PR-23 five-bit shape (`has_draft`,
/// `has_submission_response`, `has_retry_requested`,
/// `has_marked_abandoned`, `last_ack_status`):
///
///   - `has_attempt` — `InvoiceSubmissionAttempt` exists for this
///     invoice (PR-19 / ADR-0032 §4). Drives the `Pending` /
///     `PendingNavExists` labels at the state-2 ladder branch.
///   - `latest_response_is_recovered` — the most-recent
///     `InvoiceSubmissionResponse`'s `response_xml` carries
///     `<QueryInvoiceDataResponse>` bytes per ADR-0034 §4. Drives
///     the `Recovered` vs `Submitted` distinction at the state-3
///     ladder branch.
///   - `latest_check_outcome` — the most-recent
///     `InvoiceCheckPerformed`'s `outcome` field (PR-20 / ADR-0033
///     §6). Drives the `PendingNavExists` sub-label.
///   - `is_storno_base` / `is_amended_base` — set by
///     [`extract_chain_link`] from
///     `InvoiceStornoIssuedPayload` / `InvoiceModificationIssuedPayload`
///     entries whose `base_invoice_id` equals this invoice's id
///     (PR-10 / ADR-0023, PR-11 / ADR-0024). Drives the `Storno` /
///     `Amended` labels.
#[derive(Default)]
struct InvoiceTrace {
    has_draft: bool,
    /// PR-23 / ADR-0036 §2 — state-2 Pending evidence.
    has_attempt: bool,
    has_submission_response: bool,
    /// PR-23 / ADR-0036 §5 — most-recent Response's
    /// recovered-or-original discriminator.
    latest_response_is_recovered: bool,
    has_retry_requested: bool,
    has_marked_abandoned: bool,
    last_ack_status: Option<String>,
    /// PR-23 / ADR-0036 §6 — most-recent Layer-2 check outcome.
    /// Values per ADR-0033 §2: `"exists"` / `"absent"` / `"failure"`.
    latest_check_outcome: Option<String>,
    /// PR-23 / ADR-0036 §4 — base of an `InvoiceStornoIssued` chain
    /// entry. Set via [`extract_chain_link`].
    is_storno_base: bool,
    /// PR-23 / ADR-0036 §4 — base of an `InvoiceModificationIssued`
    /// chain entry. Set via [`extract_chain_link`].
    is_amended_base: bool,
}

impl InvoiceTrace {
    fn merge_entry(&mut self, entry: &Entry, invoice_id: &str) {
        match entry.kind {
            EventKind::InvoiceDraftCreated => self.has_draft = true,
            EventKind::InvoiceSubmissionAttempt => {
                // PR-23 / ADR-0036 §2 — state-2 Pending evidence.
                // The cross-invoice contamination guard parses the
                // payload's `invoice_id` field; pre-PR-23 the
                // walker collapsed Attempt into the catch-all `_`
                // arm and the Pending classification was invisible
                // at the UI layer.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceSubmissionAttemptPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_attempt = true;
                    }
                }
            }
            EventKind::InvoiceSubmissionResponse => {
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceSubmissionResponsePayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_submission_response = true;
                        // PR-23 / ADR-0036 §5 — mirror the
                        // verifier's A91 prefix-match: a response
                        // whose first ~512 bytes contain
                        // `QueryInvoiceDataResponse` was emitted
                        // by `recover-from-nav` per ADR-0034 §4.
                        // Walk is in seq order; the LAST Response
                        // wins — `latest_response_is_recovered`
                        // is overwritten on each match.
                        self.latest_response_is_recovered =
                            is_recovered_response_xml(&parsed.response_xml);
                    }
                }
            }
            EventKind::InvoiceAckStatus => {
                if let Ok(parsed) = serde_json::from_slice::<audit_payloads::InvoiceAckStatusPayload>(
                    &entry.payload,
                ) {
                    if parsed.invoice_id == invoice_id {
                        self.last_ack_status = Some(parsed.ack_status);
                    }
                }
            }
            EventKind::InvoiceCheckPerformed => {
                // PR-23 / ADR-0036 §6 — Layer-2 outcome. Mirrors
                // ADR-0033 §6's command-side informational-only
                // posture: stuck_precondition does NOT consult
                // these entries; derive_state surfaces them at the
                // label level to give the operator a separate
                // signal that recommends `recover-from-nav` over
                // `retry-submission`.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceCheckPerformedPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.latest_check_outcome = Some(parsed.outcome);
                    }
                }
            }
            EventKind::InvoiceRetryRequested => {
                self.has_retry_requested = true;
            }
            EventKind::InvoiceMarkedAbandoned => {
                self.has_marked_abandoned = true;
            }
            _ => {}
        }
    }

    /// Derive the ADR-0009 §2 typestate label from the accumulated
    /// trace. PR-23 / ADR-0036 §3 extends the pre-PR-23 six-label
    /// ladder to eleven labels with the priority ordering:
    ///
    /// ```text
    /// 1. Abandoned             (matches stuck_precondition step 1)
    /// 2. Storno                (chain-link evidence; ADR-0009 §2)
    /// 3. Amended               (chain-link evidence; ADR-0009 §2)
    /// 4. Finalized             (matches stuck_precondition AlreadyFinalized)
    /// 5. Rejected              (matches stuck_precondition AlreadyRejected)
    /// 6. Recovered             (sub-label of Submitted; ADR-0034 §4)
    /// 7. Submitted             (matches stuck_precondition AwaitingAck)
    /// 8. PendingNavExists      (sub-label of Pending; ADR-0033 §6)
    /// 9. Pending               (matches stuck_precondition Pending; ADR-0032 §4)
    /// 10. Ready                 (Draft entered the ledger; no submit yet)
    /// 11. Unknown               (no entries for this invoice)
    /// ```
    ///
    /// The mirror invariant per ADR-0036 §1: for every state both
    /// this ladder and `audit_query::stuck_precondition` can name,
    /// the two MUST agree. Drift is the failure mode the
    /// `derive_state_label_table_mirror` test pins loud per
    /// CLAUDE.md rule 12.
    fn derive_state(&self) -> InvoiceState {
        // 1. Terminal-by-operator-decision wins over everything.
        if self.has_marked_abandoned {
            return InvoiceState::Abandoned;
        }
        // 2-3. Chain-link terminal — the base invoice's typestate
        //      transition per ADR-0009 §2. Storno and Amended are
        //      orthogonal (an invoice can be the base of both over
        //      its lifetime per ADR-0024 §7); the ladder picks
        //      Storno first if both are set. Operationally rare to
        //      see both on the same base; the audit-entries view
        //      exposes the full chain to the operator.
        if self.is_storno_base {
            return InvoiceState::Storno;
        }
        if self.is_amended_base {
            return InvoiceState::Amended;
        }
        // 4-5. Terminal-by-NAV from the ack status.
        match self.last_ack_status.as_deref() {
            Some("SAVED") => return InvoiceState::Finalized,
            Some("ABORTED") => return InvoiceState::Rejected,
            _ => {}
        }
        // 6-7. State-3: Response exists, no terminal ack, no
        //      abandon. The Recovered / Submitted sub-label split
        //      mirrors ADR-0034 §4's chain-walk-by-order posture
        //      at the byte level (response_xml root element prefix
        //      per ADR-0035 §4 / A91).
        if self.has_submission_response {
            if self.latest_response_is_recovered {
                return InvoiceState::Recovered;
            }
            return InvoiceState::Submitted;
        }
        // 8-9. State-2: Attempt exists, no Response, no abandon.
        //      The PendingNavExists / Pending sub-label split
        //      mirrors ADR-0033 §6's informational-only Layer-2
        //      posture at the UI level.
        if self.has_attempt {
            if matches!(self.latest_check_outcome.as_deref(), Some("exists")) {
                return InvoiceState::PendingNavExists;
            }
            return InvoiceState::Pending;
        }
        // 10. Pre-submission: Draft entered the ledger.
        if self.has_draft {
            return InvoiceState::Ready;
        }
        // 11. No entries for this invoice id.
        InvoiceState::Unknown
    }
}

/// PR-23 / ADR-0036 §5 — recovered-Response discriminator.
///
/// Mirrors ADR-0035 §4 / A91's prefix-match local-name check at
/// the UI level: a NAV-emitted `response_xml` whose first ~512
/// bytes contain the substring `QueryInvoiceDataResponse` was
/// emitted by `recover-from-nav` per ADR-0034 §4 (which reuses
/// the existing `InvoiceSubmissionResponsePayload` shape with
/// `<QueryInvoiceDataResponse>` bytes rather than
/// `<ManageInvoiceResponse>`).
///
/// 512-byte window: the root element appears in the first ~200
/// bytes on every NAV-emitted body (XML prolog + optional
/// whitespace + optional namespace-prefixed open tag). Bounded so
/// a malformed or oversized payload doesn't scan the whole body.
///
/// Substring scan rather than exact prefix-match per
/// ADR-0036 §"Adversarial review" #2 + CLAUDE.md rule 2: the
/// dependency on quick-xml or the verifier crate's prefix-match
/// helper is not justified for the UI label split. A future PR
/// can upgrade the discriminator additively if operational
/// evidence surfaces.
fn is_recovered_response_xml(response_xml: &[u8]) -> bool {
    let window = &response_xml[..response_xml.len().min(512)];
    window
        .windows(NEEDLE_QUERY_INVOICE_DATA_RESPONSE.len())
        .any(|w| w == NEEDLE_QUERY_INVOICE_DATA_RESPONSE)
}

/// The substring scanned by [`is_recovered_response_xml`].
/// Module-level constant so the discriminator's exact bytes are
/// auditable in one place per ADR-0036 §5.
const NEEDLE_QUERY_INVOICE_DATA_RESPONSE: &[u8] = b"QueryInvoiceDataResponse";

/// PR-23 / ADR-0036 §4 — chain-link detection probe.
///
/// `InvoiceStornoIssuedPayload` and
/// `InvoiceModificationIssuedPayload` do NOT carry a top-level
/// `invoice_id` field; the existing [`extract_invoice_id`] probe
/// returns `None` for these entries. This sister probe walks the
/// per-payload chain-link fields and returns the chain entry's
/// own invoice id (`storno_invoice_id` / `modification_invoice_id`)
/// alongside the `base_invoice_id` so the BASE invoice's trace
/// can be flipped into Storno / Amended at the list-and-detail
/// walker level AND the base's detail view can list its children
/// (PR-32 / Option T).
///
/// PR-32 / session-36 — extended in place rather than forked into
/// a sister probe per reuse-over-fork (A106). The added field
/// `child_invoice_id` is the chain entry's own id, parsed from
/// whichever payload-specific field carries it; every call site
/// that previously consumed `(kind, base_id)` is updated to
/// destructure the [`ChainLink`] struct.
///
/// Returns `None` for every other `EventKind` (the typed probe
/// would fail to decode on the wrong payload shape; we
/// short-circuit on kind match first to keep the cost bounded).
fn extract_chain_link(entry: &Entry) -> Option<ChainLink> {
    #[derive(Deserialize)]
    struct StornoProbe {
        storno_invoice_id: String,
        base_invoice_id: String,
    }
    #[derive(Deserialize)]
    struct ModificationProbe {
        modification_invoice_id: String,
        base_invoice_id: String,
    }
    match entry.kind {
        EventKind::InvoiceStornoIssued => {
            let probe: StornoProbe = serde_json::from_slice(&entry.payload).ok()?;
            Some(ChainLink {
                kind: entry.kind.clone(),
                child_invoice_id: probe.storno_invoice_id,
                base_invoice_id: probe.base_invoice_id,
            })
        }
        EventKind::InvoiceModificationIssued => {
            let probe: ModificationProbe = serde_json::from_slice(&entry.payload).ok()?;
            Some(ChainLink {
                kind: entry.kind.clone(),
                child_invoice_id: probe.modification_invoice_id,
                base_invoice_id: probe.base_invoice_id,
            })
        }
        _ => None,
    }
}

/// PR-32 / session-36 — chain-link probe return shape.
///
/// Carries the two chain-link identifiers needed by every consumer:
///   - `child_invoice_id` — the chain entry's OWN invoice id (i.e.,
///     the storno or modification invoice itself).
///   - `base_invoice_id` — the BASE invoice the chain entry is
///     attached to.
///
/// Plus `kind`, the originating `EventKind` discriminant so callers
/// can match `InvoiceStornoIssued` / `InvoiceModificationIssued`
/// without re-parsing the payload.
struct ChainLink {
    kind: EventKind,
    child_invoice_id: String,
    base_invoice_id: String,
}

/// Extract the `invoice_id` field (if any) from an audit-ledger entry's
/// typed payload. Returns None for entries that don't carry an
/// invoice_id at all (none of the v3.0 payloads).
fn extract_invoice_id(entry: &Entry) -> Option<String> {
    // All current typed payloads carry an `invoice_id: String` field.
    // We parse permissively — a payload that fails to decode is
    // skipped rather than blowing up the entire serve view.
    #[derive(Deserialize)]
    struct Probe {
        invoice_id: String,
    }
    let probe: Probe = serde_json::from_slice(&entry.payload).ok()?;
    Some(probe.invoice_id)
}

