    /// Build a per-invoice trace by walking the ledger using the
    /// same probe shape `serve.rs::list_invoices` / `get_invoice_detail`
    /// use. Mirrors the production walker so test fixtures
    /// exercise the same code paths the wire surface does.
    fn trace_for(ledger: &Ledger, invoice_id: &str) -> InvoiceTrace {
        let entries = ledger.entries().unwrap();
        let mut trace = InvoiceTrace::default();
        for entry in &entries {
            if let Some(id) = extract_invoice_id(entry) {
                if id == invoice_id {
                    trace.merge_entry(entry, invoice_id);
                }
            }
            if let Some(link) = extract_chain_link(entry) {
                if link.base_invoice_id == invoice_id {
                    match link.kind {
                        EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                        EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                        _ => {}
                    }
                }
            }
        }
        trace
    }

    /// PR-23 / ADR-0036 §8 — parameterized expected-label table.
    ///
    /// Eleven scenarios, one per UI label. Each fixture builds an
    /// in-memory ledger and asserts the derived label. Drift
    /// between the ADR-0036 §3 ladder and the parameterized
    /// expectations surfaces here loud per CLAUDE.md rule 12.
    ///
    /// CLAUDE.md rule 9: each test row pins a distinct business
    /// rule. A test that passes when `derive_state` returns a
    /// constant would fail every row except `Unknown` — the
    /// per-label coverage means business-logic regressions cannot
    /// hide.
    #[test]
    fn derive_state_label_table_mirror() {
        // 1. Unknown — no entries for this invoice.
        {
            let (ledger, _actor) = fixture_ledger();
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Unknown);
        }
        // 2. Ready — Draft only.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Ready);
        }
        // 3. Pending — Attempt without Response, no Check entry.
        //    Mirrors stuck_precondition's
        //    `pending_when_attempt_exists_and_no_response`.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Pending);
        }
        // 4. PendingNavExists — Pending + latest Check is exists.
        //    ADR-0033 §6: Layer-2 entries are informational at the
        //    command-side; the UI surfaces the divergence loud.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            write_check_performed(&mut ledger, &actor, "inv_A", idem, "exists");
            assert_eq!(
                trace_for(&ledger, "inv_A").derive_state(),
                InvoiceState::PendingNavExists
            );
        }
        // 5. Submitted — Response (originally-witnessed) exists,
        //    no terminal ack. Mirrors stuck_precondition's
        //    `stuck_when_submission_response_exists_and_no_ack`.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            write_submission_response_originally_witnessed(
                &mut ledger,
                &actor,
                "inv_A",
                idem,
                "TXID-A",
            );
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Submitted);
        }
        // 6. Recovered — Response carries QueryInvoiceDataResponse
        //    bytes. ADR-0034 §4 + ADR-0035 §4 / A91.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            write_check_performed(&mut ledger, &actor, "inv_A", idem, "exists");
            write_submission_response_recovered(&mut ledger, &actor, "inv_A", idem, "TXID-A");
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Recovered);
        }
        // 7. Finalized — last ack is SAVED. Mirrors
        //    stuck_precondition's `finalized_when_last_ack_is_saved`.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            write_submission_response_originally_witnessed(
                &mut ledger,
                &actor,
                "inv_A",
                idem,
                "TXID-A",
            );
            write_ack_status(&mut ledger, &actor, "inv_A", "TXID-A", "PROCESSING");
            write_ack_status(&mut ledger, &actor, "inv_A", "TXID-A", "SAVED");
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Finalized);
        }
        // 8. Rejected — last ack is ABORTED. Mirrors
        //    stuck_precondition's `rejected_when_last_ack_is_aborted`.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            write_submission_response_originally_witnessed(
                &mut ledger,
                &actor,
                "inv_A",
                idem,
                "TXID-A",
            );
            write_ack_status(&mut ledger, &actor, "inv_A", "TXID-A", "ABORTED");
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Rejected);
        }
        // 9. Storno — InvoiceStornoIssued points at this id as
        //    base. ADR-0009 §2's Finalized → Storno transition.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem_base = IdempotencyKey::new();
            let idem_storno = IdempotencyKey::new();
            // Base went Finalized then stornod.
            write_draft(&mut ledger, &actor, "inv_A", idem_base);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem_base);
            write_submission_response_originally_witnessed(
                &mut ledger,
                &actor,
                "inv_A",
                idem_base,
                "TXID-A",
            );
            write_ack_status(&mut ledger, &actor, "inv_A", "TXID-A", "SAVED");
            // Storno's own draft (its own audit lineage) +
            // chain-link pointing at the base.
            write_draft(&mut ledger, &actor, "inv_B", idem_storno);
            write_storno_issued(&mut ledger, &actor, "inv_B", "inv_A", idem_storno);
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Storno);
            // The storno's OWN trace is `Ready` — it has its own
            // Draft but no Attempt yet. (In production the storno
            // would proceed through the same submit/poll/ack
            // lifecycle; the test fixture stops at the draft.)
            assert_eq!(trace_for(&ledger, "inv_B").derive_state(), InvoiceState::Ready);
        }
        // 10. Amended — InvoiceModificationIssued points at this id
        //     as base. ADR-0009 §2's Finalized → Amended transition.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem_base = IdempotencyKey::new();
            let idem_mod = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem_base);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem_base);
            write_submission_response_originally_witnessed(
                &mut ledger,
                &actor,
                "inv_A",
                idem_base,
                "TXID-A",
            );
            write_ack_status(&mut ledger, &actor, "inv_A", "TXID-A", "SAVED");
            write_draft(&mut ledger, &actor, "inv_M", idem_mod);
            write_modification_issued(&mut ledger, &actor, "inv_M", "inv_A", idem_mod);
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Amended);
        }
        // 11. Abandoned — InvoiceMarkedAbandoned exists. Mirrors
        //     stuck_precondition's
        //     `abandoned_wins_over_any_other_state`.
        {
            let (mut ledger, actor) = fixture_ledger();
            let idem = IdempotencyKey::new();
            write_draft(&mut ledger, &actor, "inv_A", idem);
            write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
            write_submission_response_originally_witnessed(
                &mut ledger,
                &actor,
                "inv_A",
                idem,
                "TXID-A",
            );
            write_marked_abandoned(&mut ledger, &actor, "inv_A", idem, "TXID-A");
            assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Abandoned);
        }
    }

    /// PR-23 / ADR-0036 §3 priority-ordering pin: Abandoned wins
    /// over Storno (defence-in-depth — in clean production state
    /// the two should not co-occur per the ADR-0009 §2 transition
    /// rules, but if the audit ledger ever carries both, the
    /// terminal-by-operator-decision branch wins per the
    /// authoritative classifier's posture). Mirrors
    /// `audit_query.rs::tests::already_abandoned_overrides_pending_state_2`.
    #[test]
    fn derive_state_abandoned_wins_over_storno_base() {
        let (mut ledger, actor) = fixture_ledger();
        let idem_base = IdempotencyKey::new();
        let idem_storno = IdempotencyKey::new();
        write_draft(&mut ledger, &actor, "inv_A", idem_base);
        write_submission_attempt(&mut ledger, &actor, "inv_A", idem_base);
        write_submission_response_originally_witnessed(
            &mut ledger,
            &actor,
            "inv_A",
            idem_base,
            "TXID-A",
        );
        write_ack_status(&mut ledger, &actor, "inv_A", "TXID-A", "SAVED");
        write_storno_issued(&mut ledger, &actor, "inv_B", "inv_A", idem_storno);
        write_marked_abandoned(&mut ledger, &actor, "inv_A", idem_base, "TXID-A");
        assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Abandoned);
    }

    /// PR-23 / ADR-0036 §3 priority-ordering pin: Recovered wins
    /// over Submitted (the state-3 sub-label split). If the most-
    /// recent Response is a recovered one, the label is
    /// `Recovered`; if it's an originally-witnessed one, the label
    /// is `Submitted`. Order in the ledger matters — the LAST
    /// Response wins.
    #[test]
    fn derive_state_latest_response_wins_for_recovered_split() {
        let (mut ledger, actor) = fixture_ledger();
        let idem = IdempotencyKey::new();
        write_draft(&mut ledger, &actor, "inv_A", idem);
        write_submission_attempt(&mut ledger, &actor, "inv_A", idem);
        // Earlier: an originally-witnessed Response.
        write_submission_response_originally_witnessed(
            &mut ledger,
            &actor,
            "inv_A",
            idem,
            "TXID-A",
        );
        // Later: a recovered Response (in practice the recover-
        // from-nav precondition guard prevents this, but the UI
        // walker handles whatever the ledger carries).
        write_submission_response_recovered(&mut ledger, &actor, "inv_A", idem, "TXID-B");
        assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Recovered);
    }

    /// PR-23 / ADR-0036 §5 substring-scan discriminator pin:
    /// `is_recovered_response_xml` MUST return true for the
    /// `<QueryInvoiceDataResponse>` root element AND for the
    /// namespace-prefixed form `<ns0:QueryInvoiceDataResponse>`,
    /// and MUST return false for the `<ManageInvoiceResponse>`
    /// originally-witnessed form. CLAUDE.md rule 9: the
    /// discriminator is the load-bearing signal for the
    /// Recovered / Submitted split; a regression would silently
    /// collapse Recovered into Submitted.
    #[test]
    fn is_recovered_response_xml_prefix_match() {
        assert!(is_recovered_response_xml(
            b"<QueryInvoiceDataResponse/>"
        ));
        assert!(is_recovered_response_xml(
            b"<?xml version=\"1.0\"?><ns0:QueryInvoiceDataResponse xmlns:ns0=\"http://schemas.nav.gov.hu/OSA/3.0/api\"/>"
        ));
        assert!(!is_recovered_response_xml(
            b"<?xml version=\"1.0\"?><ManageInvoiceResponse><transactionId>TXID</transactionId></ManageInvoiceResponse>"
        ));
        assert!(!is_recovered_response_xml(b""));
        // Per ADR-0036 §5 the scan window is bounded to 512 bytes.
        // A discriminator literal far past the window MUST NOT
        // match. Bound the test fixture explicitly.
        let mut padded = vec![b' '; 800];
        padded.extend_from_slice(b"<QueryInvoiceDataResponse/>");
        assert!(
            !is_recovered_response_xml(&padded),
            "discriminator past the 512-byte window must not match"
        );
    }

    /// PR-26 / session-30 — `audit_view_of` MUST surface the
    /// chain-link `base_invoice_id` for `InvoiceStornoIssued` and
    /// `InvoiceModificationIssued` entries, and MUST emit `None` for
    /// every other `EventKind`. The SPA's chain-link click handler
    /// in `InvoiceDetail.svelte` depends on this field; a silent
    /// regression (probe replaced with `None`) would collapse the
    /// inspector affordance per CLAUDE.md rule 12. The field's
    /// `Option<String>` shape is the load-bearing contract — the
    /// SPA TS interface mirrors it as `string | null`.
    #[test]
    fn audit_view_of_emits_chain_base_invoice_id() {
        let (mut ledger, actor) = fixture_ledger();
        let idem_base = IdempotencyKey::new();
        let idem_storno = IdempotencyKey::new();
        let idem_mod = IdempotencyKey::new();

        write_draft(&mut ledger, &actor, "inv_BASE", idem_base);
        write_storno_issued(&mut ledger, &actor, "inv_STORNO", "inv_BASE", idem_storno);
        write_modification_issued(&mut ledger, &actor, "inv_MOD", "inv_BASE", idem_mod);

        let entries = ledger.entries().unwrap();
        let by_kind = |kind: EventKind| {
            entries
                .iter()
                .find(|e| e.kind == kind)
                .unwrap_or_else(|| panic!("missing entry of kind {kind:?}"))
        };

        let draft_view = audit_view_of(by_kind(EventKind::InvoiceDraftCreated));
        assert_eq!(draft_view.chain_base_invoice_id, None);

        let storno_view = audit_view_of(by_kind(EventKind::InvoiceStornoIssued));
        assert_eq!(
            storno_view.chain_base_invoice_id.as_deref(),
            Some("inv_BASE"),
        );

        let mod_view = audit_view_of(by_kind(EventKind::InvoiceModificationIssued));
        assert_eq!(mod_view.chain_base_invoice_id.as_deref(), Some("inv_BASE"));
    }

    /// PR-27 / session-31 — `audit_view_of` MUST surface the full
    /// typed payload as a JSON object on the `payload` field. The
    /// SPA's per-row drill-down in `InvoiceDetail.svelte` depends on
    /// every typed field (chain digests, idempotency keys, NAV-emitted
    /// timestamps, ack-status strings) being readable; a silent
    /// regression (probe replaced with `Null` or with an empty
    /// object) would collapse the inspector affordance per
    /// CLAUDE.md rule 12. Three kinds covered — Draft (a thin
    /// payload), Attempt (a payload with a byte-array field), Storno
    /// (the chain-link payload whose `base_invoice_id` field is the
    /// existing chain-link affordance's source of truth). Each
    /// assertion pins a distinct typed field per CLAUDE.md rule 9
    /// so a regression cannot hide behind a single shape mismatch.
    #[test]
    fn audit_view_of_emits_typed_payload() {
        let (mut ledger, actor) = fixture_ledger();
        let idem_a = IdempotencyKey::new();
        let idem_s = IdempotencyKey::new();
        write_draft(&mut ledger, &actor, "inv_A", idem_a);
        write_submission_attempt(&mut ledger, &actor, "inv_A", idem_a);
        write_storno_issued(&mut ledger, &actor, "inv_S", "inv_A", idem_s);

        let entries = ledger.entries().unwrap();
        let by_kind = |kind: EventKind| {
            entries
                .iter()
                .find(|e| e.kind == kind)
                .unwrap_or_else(|| panic!("missing entry of kind {kind:?}"))
        };

        let draft_view = audit_view_of(by_kind(EventKind::InvoiceDraftCreated));
        let obj = draft_view
            .payload
            .as_object()
            .expect("Draft payload must serialise as a JSON object");
        assert_eq!(
            obj.get("invoice_id").and_then(|v| v.as_str()),
            Some("inv_A")
        );
        assert!(obj.contains_key("line_count"));
        assert!(obj.contains_key("idempotency_key"));
        assert!(obj.contains_key("nav_xml_path"));

        let attempt_view = audit_view_of(by_kind(EventKind::InvoiceSubmissionAttempt));
        let obj = attempt_view
            .payload
            .as_object()
            .expect("Attempt payload must serialise as a JSON object");
        assert_eq!(
            obj.get("invoice_id").and_then(|v| v.as_str()),
            Some("inv_A")
        );
        assert!(obj.contains_key("endpoint"));
        assert!(obj.contains_key("request_xml"));

        let storno_view = audit_view_of(by_kind(EventKind::InvoiceStornoIssued));
        let obj = storno_view
            .payload
            .as_object()
            .expect("Storno payload must serialise as a JSON object");
        assert_eq!(
            obj.get("base_invoice_id").and_then(|v| v.as_str()),
            Some("inv_A"),
        );
        assert_eq!(
            obj.get("storno_invoice_id").and_then(|v| v.as_str()),
            Some("inv_S"),
        );
        assert!(obj.contains_key("modification_index"));
    }

    /// PR-23 / ADR-0036 §4 cross-invoice contamination pin: a
    /// Storno chain-link for inv_B as base MUST NOT flip inv_A's
    /// trace into Storno. Mirrors
    /// `audit_query.rs::tests::precondition_does_not_cross_invoice_ids`
    /// at the chain-link probe level.
    #[test]
    fn chain_base_link_does_not_cross_invoice_ids() {
        let (mut ledger, actor) = fixture_ledger();
        let idem_a = IdempotencyKey::new();
        let idem_b = IdempotencyKey::new();
        let idem_storno = IdempotencyKey::new();
        write_draft(&mut ledger, &actor, "inv_A", idem_a);
        write_draft(&mut ledger, &actor, "inv_B", idem_b);
        // Storno points at inv_B as base.
        write_storno_issued(&mut ledger, &actor, "inv_S", "inv_B", idem_storno);
        // inv_A is unaffected — still Ready.
        assert_eq!(trace_for(&ledger, "inv_A").derive_state(), InvoiceState::Ready);
        // inv_B IS flipped.
        assert_eq!(trace_for(&ledger, "inv_B").derive_state(), InvoiceState::Storno);
    }

    /// PR-28 / ADR-0036 §9 — the typed `InvoiceState` enum MUST
    /// serialise each variant to the exact PascalCase string the SPA
    /// expects in `apps/aberp-ui/ui/src/lib/api.ts`. A silent rename
    /// at either end (e.g., adding `#[serde(rename_all = ...)]` to
    /// the enum, or a typo in the SPA union) would diverge the wire
    /// shape and the SPA's `labelMeta` fallback would show every row
    /// as a muted "?" pill. CLAUDE.md rule 12: pin the contract loud.
    ///
    /// CLAUDE.md rule 9: per-variant coverage means a regression
    /// that collapses all variants to one string (or returns a
    /// constant) cannot hide behind a single matching assertion.
    #[test]
    fn invoice_state_wire_shape_pins_pascalcase_strings() {
        let cases: [(InvoiceState, &str); 11] = [
            (InvoiceState::Unknown, "Unknown"),
            (InvoiceState::Ready, "Ready"),
            (InvoiceState::Pending, "Pending"),
            (InvoiceState::PendingNavExists, "PendingNavExists"),
            (InvoiceState::Submitted, "Submitted"),
            (InvoiceState::Recovered, "Recovered"),
            (InvoiceState::Finalized, "Finalized"),
            (InvoiceState::Rejected, "Rejected"),
            (InvoiceState::Storno, "Storno"),
            (InvoiceState::Amended, "Amended"),
            (InvoiceState::Abandoned, "Abandoned"),
        ];
        for (variant, expected) in cases {
            let value = serde_json::to_value(variant)
                .expect("InvoiceState variants must always serialise");
            assert_eq!(
                value,
                serde_json::Value::String(expected.to_string()),
                "InvoiceState::{variant:?} wire form drifted from `{expected}`",
            );
        }
    }

    /// PR-31 / session-35 — `InvoiceListItem` MUST carry a typed
    /// `has_chain_children: bool` field on the JSON wire shape per
    /// the session-30-named Option M lift. The SPA's `InvoiceList`
    /// renderer reads this field strictly (the TS interface in
    /// `apps/aberp-ui/ui/src/lib/api.ts` types it as `boolean`); a
    /// silent field rename or removal would diverge the wire shape
    /// and collapse the chain-link badge for every row. CLAUDE.md
    /// rule 12: pin the contract loud.
    ///
    /// CLAUDE.md rule 9: both `true` and `false` cases are covered
    /// so a regression that hard-codes the field to one value (or
    /// to `null` via a serde rename gone wrong) cannot pass both
    /// assertions vacuously.
    ///
    /// The production derivation
    /// (`has_chain_children: trace.is_storno_base ||
    /// trace.is_amended_base`) is pinned at the trace level by the
    /// existing `derive_state_label_table_mirror` test, which
    /// exercises both Storno-base and Amended-base scenarios through
    /// the same `trace_for` walker used by `list_invoices`. A
    /// regression that swaps the production OR for an AND or for a
    /// single flag would surface as a Storno or Amended row whose
    /// state chip is correct (still set by `derive_state`) but whose
    /// `has_chain_children` flag is wrong — caught at the integration
    /// level by an operator survey rather than at unit-test time.
    /// The wire-shape pin below catches the type and field-name
    /// drift; the derivation drift remains a code-review surface
    /// per the session-35 lean.
    #[test]
    fn invoice_list_item_emits_has_chain_children() {
        let with_chain = InvoiceListItem {
            invoice_id: "inv_BASE".to_string(),
            sequence_number: 42,
            fiscal_year: 2026,
            state: InvoiceState::Storno,
            total_gross: Some(123_456),
            has_chain_children: true,
        };
        let v = serde_json::to_value(&with_chain)
            .expect("InvoiceListItem must always serialise");
        assert_eq!(
            v.get("has_chain_children").and_then(|x| x.as_bool()),
            Some(true),
            "has_chain_children must serialise as a JSON boolean (true case)",
        );

        let without_chain = InvoiceListItem {
            invoice_id: "inv_PLAIN".to_string(),
            sequence_number: 1,
            fiscal_year: 2026,
            state: InvoiceState::Ready,
            total_gross: None,
            has_chain_children: false,
        };
        let v = serde_json::to_value(&without_chain)
            .expect("InvoiceListItem must always serialise");
        assert_eq!(
            v.get("has_chain_children").and_then(|x| x.as_bool()),
            Some(false),
            "has_chain_children must serialise as a JSON boolean (false case)",
        );
    }

    /// PR-32 / session-36 — `InvoiceDetailResponse` MUST carry a
    /// `chain_children: ChainChildView[]` field on the JSON wire
    /// shape per the session-35-named Option T lift. The SPA's
    /// `InvoiceDetail` modal reads this list strictly (the TS
    /// interface in `apps/aberp-ui/ui/src/lib/api.ts` types it as
    /// `ChainChildView[]`); a silent field rename, removal, or
    /// re-shape (e.g., `kind` swapped from the typed PascalCase
    /// enum to a free-string) would diverge the wire shape and
    /// collapse the chain-children section. CLAUDE.md rule 12:
    /// pin the contract loud.
    ///
    /// CLAUDE.md rule 9: BOTH the empty-list case and the
    /// two-children-of-different-kinds case are covered so a
    /// regression that hard-codes the field (or returns a
    /// constant) cannot pass both assertions vacuously. The
    /// kinds-of-different-kinds case also pins the
    /// `ChainChildKind::Storno` / `Amended` wire form to the
    /// PascalCase strings `"Storno"` / `"Amended"` so a future
    /// serde-rename gone wrong is caught here rather than at the
    /// SPA labels-table lookup.
    ///
    /// The production derivation (the chain-children walker pass
    /// in `get_invoice_detail` that pushes a `ChainChildView` per
    /// matching chain entry) is exercised end-to-end by
    /// `derive_state_label_table_mirror` indirectly via the same
    /// `trace_for` walker shape; this pin catches the WIRE drift
    /// independent of the walker drift.
    #[test]
    fn invoice_detail_emits_chain_children() {
        // Empty-list case — every non-chain-base invoice must
        // serialise an empty array for the field (NOT `null`,
        // NOT a missing key) so the SPA's strict TS read
        // (`ChainChildView[]`) does not need an undefined guard.
        let empty = InvoiceDetailResponse {
            invoice_id: "inv_PLAIN".to_string(),
            sequence_number: 1,
            fiscal_year: 2026,
            state: InvoiceState::Ready,
            total_gross: None,
            audit_entries: Vec::new(),
            chain_children: Vec::new(),
            last_ack_status: None,
        };
        let v = serde_json::to_value(&empty)
            .expect("InvoiceDetailResponse must always serialise");
        let arr = v
            .get("chain_children")
            .and_then(|x| x.as_array())
            .expect("chain_children must serialise as a JSON array");
        assert!(
            arr.is_empty(),
            "chain_children must serialise as an empty array when there are no children",
        );

        // Non-empty case — two children of different kinds. Pins
        // both the per-entry shape (`{kind, invoice_id}`) AND the
        // PascalCase wire form of the two `ChainChildKind`
        // variants.
        let with_chain = InvoiceDetailResponse {
            invoice_id: "inv_BASE".to_string(),
            sequence_number: 42,
            fiscal_year: 2026,
            state: InvoiceState::Storno,
            total_gross: Some(123_456),
            audit_entries: Vec::new(),
            chain_children: vec![
                ChainChildView {
                    kind: ChainChildKind::Amended,
                    invoice_id: "inv_MOD".to_string(),
                },
                ChainChildView {
                    kind: ChainChildKind::Storno,
                    invoice_id: "inv_STORNO".to_string(),
                },
            ],
            last_ack_status: None,
        };
        let v = serde_json::to_value(&with_chain)
            .expect("InvoiceDetailResponse must always serialise");
        let arr = v
            .get("chain_children")
            .and_then(|x| x.as_array())
            .expect("chain_children must serialise as a JSON array");
        assert_eq!(arr.len(), 2, "two chain children must round-trip");

        assert_eq!(
            arr[0].get("kind").and_then(|x| x.as_str()),
            Some("Amended"),
            "ChainChildKind::Amended must serialise as PascalCase `Amended`",
        );
        assert_eq!(
            arr[0].get("invoice_id").and_then(|x| x.as_str()),
            Some("inv_MOD"),
            "chain child invoice_id must serialise verbatim",
        );

        assert_eq!(
            arr[1].get("kind").and_then(|x| x.as_str()),
            Some("Storno"),
            "ChainChildKind::Storno must serialise as PascalCase `Storno`",
        );
        assert_eq!(
            arr[1].get("invoice_id").and_then(|x| x.as_str()),
            Some("inv_STORNO"),
            "chain child invoice_id must serialise verbatim",
        );
    }

    /// PR-33 / session-37 — the typed `AckStatus` enum MUST serialise
    /// each variant to the exact UPPERCASE string NAV v3.0 emits on
    /// the inbound parse path and the SPA expects in
    /// `apps/aberp-ui/ui/src/lib/api.ts`. A silent rename at either
    /// end (e.g., dropping `#[serde(rename_all = "UPPERCASE")]` on
    /// the enum, swapping it for SCREAMING_SNAKE_CASE, or a typo in
    /// the SPA `AckStatus` union) would diverge the wire shape from
    /// the persisted form in `InvoiceAckStatusPayload.ack_status` and
    /// collapse the detail-modal "Latest ack" meta-grid value to an
    /// empty render. CLAUDE.md rule 12: pin the contract loud.
    ///
    /// CLAUDE.md rule 9: per-variant coverage means a regression that
    /// collapses all variants to one string (or to PascalCase) cannot
    /// hide behind a single matching assertion.
    ///
    /// Mirror invariant with `parse_ack_status` covered by
    /// `ack_status_parse_round_trip`: every variant that serialises to
    /// a UPPERCASE string MUST parse back from that same string. The
    /// pair prevents a one-sided rename that would let serialise and
    /// parse drift.
    #[test]
    fn ack_status_wire_shape_pins_uppercase_strings() {
        let cases: [(AckStatus, &str); 4] = [
            (AckStatus::Received, "RECEIVED"),
            (AckStatus::Processing, "PROCESSING"),
            (AckStatus::Saved, "SAVED"),
            (AckStatus::Aborted, "ABORTED"),
        ];
        for (variant, expected) in cases {
            let value = serde_json::to_value(variant)
                .expect("AckStatus variants must always serialise");
            assert_eq!(
                value,
                serde_json::Value::String(expected.to_string()),
                "AckStatus::{variant:?} wire form drifted from `{expected}`",
            );
        }
    }

    /// PR-33 / session-37 — `parse_ack_status` MUST round-trip with
    /// `Serialize` for every variant. A regression that re-cases the
    /// match arms (e.g., to PascalCase) without re-casing the serde
    /// rename would let `get_invoice_detail` emit `null` for every
    /// invoice and the operator would see a permanent `—` in the
    /// "Latest ack" cell — a silent failure mode rather than a loud
    /// one. The round-trip pins both sides at the same call site so
    /// the drift is impossible.
    ///
    /// Also pins the two unknown-input behaviours used by the
    /// production path: a non-NAV string parses to `None` (so the
    /// wire field falls back to `null` rather than failing the read
    /// endpoint), and the empty string also parses to `None`.
    #[test]
    fn ack_status_parse_round_trip() {
        for variant in [
            AckStatus::Received,
            AckStatus::Processing,
            AckStatus::Saved,
            AckStatus::Aborted,
        ] {
            let wire = serde_json::to_value(variant)
                .expect("AckStatus must serialise");
            let s = wire.as_str().expect("AckStatus emits a string");
            assert_eq!(
                parse_ack_status(s),
                Some(variant),
                "AckStatus::{variant:?} wire `{s}` must parse back to the same variant",
            );
        }
        assert_eq!(
            parse_ack_status("DONE"),
            None,
            "deprecated pre-v3.0 `DONE` must NOT parse — NAV v3.0 dropped it",
        );
        assert_eq!(
            parse_ack_status(""),
            None,
            "empty string must NOT parse to any AckStatus variant",
        );
        assert_eq!(
            parse_ack_status("saved"),
            None,
            "lowercase must NOT parse — wire form is strictly UPPERCASE per NAV v3.0",
        );
    }

    /// PR-33 / session-37 — `InvoiceDetailResponse` MUST carry a
    /// typed `last_ack_status: Option<AckStatus>` field on the JSON
    /// wire shape per the session-36-named Option Q lift. The SPA's
    /// `InvoiceDetail` modal reads this field strictly (the TS
    /// interface in `apps/aberp-ui/ui/src/lib/api.ts` types it as
    /// `AckStatus | null`); a silent field rename, removal, or
    /// re-shape would diverge the wire shape and collapse the
    /// detail-modal "Latest ack" cell. CLAUDE.md rule 12: pin the
    /// contract loud.
    ///
    /// CLAUDE.md rule 9: BOTH the `None` (null) case AND each of the
    /// four `Some` cases are covered so a regression that hard-codes
    /// the field to a single value cannot pass every assertion
    /// vacuously. Together with
    /// `ack_status_wire_shape_pins_uppercase_strings` this pins the
    /// per-variant wire-emit AND the field-presence-plus-shape on
    /// the parent struct.
    #[test]
    fn invoice_detail_emits_last_ack_status() {
        // Null case — an invoice with no ack yet must serialise the
        // field as JSON `null` (NOT a missing key) so the SPA's
        // strict TS read (`AckStatus | null`) does not need an
        // undefined guard.
        let none = InvoiceDetailResponse {
            invoice_id: "inv_NONE".to_string(),
            sequence_number: 1,
            fiscal_year: 2026,
            state: InvoiceState::Ready,
            total_gross: None,
            audit_entries: Vec::new(),
            chain_children: Vec::new(),
            last_ack_status: None,
        };
        let v = serde_json::to_value(&none)
            .expect("InvoiceDetailResponse must always serialise");
        assert!(
            v.get("last_ack_status").map(|x| x.is_null()).unwrap_or(false),
            "last_ack_status must serialise as JSON null when there is no ack",
        );

        // Each Some variant — covers all four NAV v3.0 values
        // through the parent struct's serialisation path. The wire
        // emit on the parent must match the per-variant pin from
        // `ack_status_wire_shape_pins_uppercase_strings`.
        let cases: [(AckStatus, &str); 4] = [
            (AckStatus::Received, "RECEIVED"),
            (AckStatus::Processing, "PROCESSING"),
            (AckStatus::Saved, "SAVED"),
            (AckStatus::Aborted, "ABORTED"),
        ];
        for (variant, expected) in cases {
            let some = InvoiceDetailResponse {
                invoice_id: "inv_SOME".to_string(),
                sequence_number: 7,
                fiscal_year: 2026,
                state: InvoiceState::Submitted,
                total_gross: Some(1_000),
                audit_entries: Vec::new(),
                chain_children: Vec::new(),
                last_ack_status: Some(variant),
            };
            let v = serde_json::to_value(&some)
                .expect("InvoiceDetailResponse must always serialise");
            assert_eq!(
                v.get("last_ack_status").and_then(|x| x.as_str()),
                Some(expected),
                "last_ack_status must serialise AckStatus::{variant:?} as `{expected}`",
            );
        }
    }
